const csvData = $json.data || '';

if (!csvData || csvData.trim().length === 0) {
  console.log('⚠️ No data returned from API');
  return [{ json: { _empty: true } }];
}

function parseCSVLine(line) {
  const vals = [];
  let inQuotes = false;
  let current = '';

  for (let i = 0; i < line.length; i++) {
    const c = line[i];

    if (c === '"' && (i === 0 || line[i - 1] !== '\\')) {
      inQuotes = !inQuotes;
      continue;
    }

    if (c === ',' && !inQuotes) {
      vals.push(current);
      current = '';
      continue;
    }

    current += c;
  }

  vals.push(current);
  return vals.map(v => v.trim());
}

const lines = csvData.trim().split(/\r?\n/);
const headers = parseCSVLine(lines[0]);

console.log('📊 Winners CSV Headers:', headers);

const parsedAccounts = [];

for (let i = 1; i < lines.length; i++) {
  const vals = parseCSVLine(lines[i]);
  if (vals.length !== headers.length) continue;

  const account = {};
  headers.forEach((h, idx) => {
    account[h] = vals[idx] || '';
  });

  parsedAccounts.push(account);
}

console.log(`✅ Parsed ${parsedAccounts.length} winner accounts from CSV`);

if (parsedAccounts.length === 0) {
  return [{ json: { _empty: true } }];
}
return parsedAccounts.map(a => ({ json: a }));

/**
 * Extract Winner Metrics
 * Extracts all fields, computes derived ratios, takes top 30 by closed_won count descending.
 */

const items = $input.all();

if (items.length === 0 || (items.length === 1 && items[0].json._empty)) {
  console.log('⚠️ No winner data to extract');
  return [{ json: { _empty: true, winners: [] } }];
}

console.log(`🔍 Extract Winner Metrics: Processing ${items.length} items`);

function findHeader(obj, keywords) {
  const keys = Object.keys(obj);
  for (const keyword of keywords) {
    const found = keys.find(k => k.toLowerCase().includes(keyword.toLowerCase()));
    if (found) return found;
  }
  return null;
}

function toNumber(x) {
  const n = Number(String(x || '').replace(/[,$]/g, ''));
  return Number.isFinite(n) ? n : 0;
}

const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i].json;

  if (i === 0) console.log('📋 Available keys:', Object.keys(item).join(', '));

  const accountId = item['Account ID'] || item.ootb_account_id || 'Unknown';
  const accountName = item['Account Name'] || item.ootb_account_name || 'Unknown';
  const accountOwner = item['Account Owner (name)'] || item.ootb_account_original_owner || 'Unassigned';
  const accountDomain = item['Account Domain'] || item.ootb_account_domain || '';
  const engagementLevel = toNumber(item['Account Engagement Level'] || item.ootb_account_engagement_level);
  const industry = item['Account Industry'] || item.ootb_account_industry || '';

  const annualRevenueKey = findHeader(item, ['annual_revenue', 'annual revenue', 'Annual Revenue']);
  const annualRevenue = toNumber(annualRevenueKey ? item[annualRevenueKey] : 0);

  const meetings30dKey = findHeader(item, ['meetings_standard_last_30_days', 'Meetings (Last 30 Days)']);
  const meetings30d = toNumber(meetings30dKey ? item[meetings30dKey] : 0);

  const emails30dKey = findHeader(item, ['count_of_emails_last_30_days', 'Emails (Last 30 Days)']);
  const emails30d = toNumber(emails30dKey ? item[emails30dKey] : 0);

  const emailsSentKey = findHeader(item, ['emails_sent_last_30', 'Emails Sent (Last 30 Days)']);
  const emailsSent30d = toNumber(emailsSentKey ? item[emailsSentKey] : 0);

  const emailsReceivedKey = findHeader(item, ['emails_received_last_30', 'Emails Received (Last 30 Days)']);
  const emailsReceived30d = toNumber(emailsReceivedKey ? item[emailsReceivedKey] : 0);

  const peopleContacted30dKey = findHeader(item, ['external_people_contacted_last_30', 'External People Contacted (Last 30 Days)']);
  const peopleContacted30d = toNumber(peopleContacted30dKey ? item[peopleContacted30dKey] : 0);

  const peopleContacted7dKey = findHeader(item, ['external_people_contacted_last_7', 'External People Contacted (Last 7 Days)']);
  const peopleContacted7d = toNumber(peopleContacted7dKey ? item[peopleContacted7dKey] : 0);

  const execsEngagedKey = findHeader(item, ['engaged_executives_external_last_30', 'Engaged Executives (Last 30 Days)']);
  const execsEngaged30d = toNumber(execsEngagedKey ? item[execsEngagedKey] : 0);

  const execActivitiesKey = findHeader(item, ['executive_activities_last_30', 'Executive Activities (Last 30 Days)']);
  const execActivities30d = toNumber(execActivitiesKey ? item[execActivitiesKey] : 0);

  const peopleEngagedKey = findHeader(item, ['people_engaged_last_30', 'People Engaged (Last 30 Days)']);
  const peopleEngaged30d = toNumber(peopleEngagedKey ? item[peopleEngagedKey] : 0);

  const closedWonKey = findHeader(item, ['closed_won_opportunities_last_fyear', 'Closed Won Opportunities (Last FYear)']);
  const closedWon = toNumber(closedWonKey ? item[closedWonKey] : 0);

  const totalActivity = meetings30d + emails30d;
  const meetingRatio = totalActivity > 0 ? meetings30d / totalActivity : 0;
  const execRatio = peopleContacted30d > 0 ? execsEngaged30d / peopleContacted30d : 0;
  const emailResponsiveness = emailsSent30d > 0 ? emailsReceived30d / emailsSent30d : 0;
  const contactVelocityProxy = peopleContacted30d > 0 ? (peopleContacted7d / peopleContacted30d) * 4.286 : 0;
  const stakeholderBreadth = peopleContacted30d / 4.3;

  results.push({
    accountId, accountName, accountOwner, accountDomain, engagementLevel, industry, annualRevenue,
    meetings30d, emails30d, emailsSent30d, emailsReceived30d, peopleContacted30d, peopleContacted7d,
    execsEngaged30d, execActivities30d, peopleEngaged30d, closedWon,
    meetingRatio: Math.round(meetingRatio * 1000) / 1000,
    execRatio: Math.round(execRatio * 1000) / 1000,
    emailResponsiveness: Math.round(emailResponsiveness * 1000) / 1000,
    contactVelocityProxy: Math.round(contactVelocityProxy * 1000) / 1000,
    stakeholderBreadth: Math.round(stakeholderBreadth * 100) / 100
  });
}

results.sort((a, b) => b.closedWon - a.closedWon);
const top30 = results.slice(0, 30);

console.log(`✅ Extracted ${results.length} total winners, returning top ${top30.length} by closed-won count`);

return [{ json: { winners: top30, totalWinners: top30.length } }];

