function markdownToHtml(text) {
  let html = text
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/\*(.+?)\*/g, '<em>$1</em>')
    .replace(/\|(.+)\|/g, function(match) {
      const cells = match.split('|').filter(c => c.trim());
      if (cells.every(c => /^[\s-:]+$/.test(c))) return '';
      const isHeader = cells.every(c => /^\s*[A-Z]/.test(c.trim()));
      const tag = isHeader ? 'th' : 'td';
      const style = isHeader
        ? 'style="padding: 10px 12px; background-color: #7c3aed; color: white; font-size: 12px; text-align: left; font-weight: 600;"'
        : 'style="padding: 10px 12px; border-bottom: 1px solid #e5e7eb; font-size: 13px;"';
      return '<tr>' + cells.map(c => `<${tag} ${style}>${c.trim()}</${tag}>`).join('') + '</tr>';
    })
    .replace(/^-\s+(.+)$/gm, '<li style="margin-bottom: 6px; font-size: 14px;">$1</li>')
    .replace(/^(\d+)\.\s+(.+)$/gm, '<li style="margin-bottom: 8px; font-size: 14px;"><strong>$1.</strong> $2</li>')
    .replace(/\n\n/g, '</p><p style="margin: 12px 0; font-size: 14px; line-height: 1.6; color: #374151;">')
    .replace(/\n/g, '<br>');

  if (html.includes('<tr>')) {
    html = html.replace(/(<tr>.*?<\/tr>)+/gs, '<table style="width: 100%; border-collapse: collapse; margin: 16px 0; border: 1px solid #e5e7eb;">$&</table>');
  }
  if (html.includes('<li')) {
    html = html.replace(/(<li[^>]*>.*?<\/li>)+/gs, '<ul style="margin: 12px 0; padding-left: 24px;">$&</ul>');
  }

  return html;
}

const bodyHtml = markdownToHtml(aiOutput);

let html = `<!DOCTYPE html><html><head><meta charset="UTF-8"><title>ICP Calibration</title></head><body style="margin: 0; padding: 0; background-color: #f3f4f6; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Arial, sans-serif;"><div style="max-width: 800px; margin: 0 auto; background-color: #ffffff;"><div style="background: linear-gradient(135deg, #7c3aed 0%, #5b21b6 100%); color: #ffffff; padding: 40px 32px; text-align: center;"><h1 style="margin: 0; font-size: 32px; font-weight: 700;">🎯 ICP Calibration Complete</h1><p style="margin: 8px 0 0 0; font-size: 16px; opacity: 0.9;">Win Pattern Fingerprint \u2022 ${today}</p><p style="margin: 4px 0 0 0; font-size: 14px; opacity: 0.75;">Requested by ${userName}</p></div><div style="padding: 32px;"><p style="margin: 12px 0; font-size: 14px; line-height: 1.6; color: #374151;">${bodyHtml}</p></div><div style="background-color: #f9fafb; padding: 24px 32px; border-top: 1px solid #e5e7eb; text-align: center;"><p style="margin: 0; color: #6b7280; font-size: 13px;">Powered by ICP Calibration \u2022 People.ai + Claude AI \u2022 ${today}</p></div></div></body></html>`;

return [{ json: { htmlEmail: html, subject: `ICP Calibration - Win Pattern Fingerprint - ${today}` } }];

