const csvData = $json.data || '';

if (!csvData || csvData.trim().length === 0) {
  console.log('⚠️ No data returned from API');
  return [{ json: { _empty: true } }];
}

function parseCSVLine(line) {
  const vals = [];
  let inQuotes = false;
  let current = '';

  for (let i = 0; i < line.length; i++) {
    const c = line[i];

    if (c === '"' && (i === 0 || line[i - 1] !== '\\')) {
      inQuotes = !inQuotes;
      continue;
    }

    if (c === ',' && !inQuotes) {
      vals.push(current);
      current = '';
      continue;
    }

    current += c;
  }

  vals.push(current);
  return vals.map(v => v.trim());
}

const lines = csvData.trim().split(/\r?\n/);
const headers = parseCSVLine(lines[0]);

console.log('📊 Target Accounts CSV Headers:', headers);

const parsedAccounts = [];

for (let i = 1; i < lines.length; i++) {
  const vals = parseCSVLine(lines[i]);
  if (vals.length !== headers.length) continue;

  const account = {};
  headers.forEach((h, idx) => {
    account[h] = vals[idx] || '';
  });

  parsedAccounts.push(account);
}

console.log(`✅ Parsed ${parsedAccounts.length} low-engagement accounts from CSV`);

if (parsedAccounts.length === 0) {
  return [{ json: { _empty: true } }];
}
return parsedAccounts.map(a => ({ json: a }));

/**
 * Extract Target Data
 * Extract fields, compute firmographic score, sort by revenue desc, take top 30
 */

const items = $input.all();

if (items.length === 0 || (items.length === 1 && items[0].json._empty)) {
  console.log('⚠️ No target account data to extract');
  return [{ json: { _empty: true, targets: [] } }];
}

console.log(`🔍 Extract Target Data: Processing ${items.length} items`);

function findHeader(obj, keywords) {
  const keys = Object.keys(obj);
  for (const keyword of keywords) {
    const found = keys.find(k => k.toLowerCase().includes(keyword.toLowerCase()));
    if (found) return found;
  }
  return null;
}

function toNumber(x) {
  const n = Number(String(x || '').replace(/[,$]/g, ''));
  return Number.isFinite(n) ? n : 0;
}

const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i].json;

  if (i === 0) console.log('📋 Available keys:', Object.keys(item).join(', '));

  const accountId = item['Account ID'] || item.ootb_account_id || 'Unknown';
  const accountName = item['Account Name'] || item.ootb_account_name || 'Unknown';
  const accountOwner = item['Account Owner (name)'] || item.ootb_account_original_owner || 'Unassigned';
  const accountDomain = item['Account Domain'] || item.ootb_account_domain || '';
  const industry = item['Account Industry'] || item.ootb_account_industry || '';
  const accountType = item['Account Type'] || item.ootb_account_type || '';
  const engagementLevel = toNumber(item['Account Engagement Level'] || item.ootb_account_engagement_level);

  const annualRevenueKey = findHeader(item, ['annual_revenue', 'annual revenue', 'Annual Revenue']);
  const annualRevenue = toNumber(annualRevenueKey ? item[annualRevenueKey] : 0);

  const meetings30dKey = findHeader(item, ['meetings_standard_last_30_days', 'Meetings (Last 30 Days)']);
  const meetings30d = toNumber(meetings30dKey ? item[meetings30dKey] : 0);

  const emails30dKey = findHeader(item, ['count_of_emails_last_30_days', 'Emails (Last 30 Days)']);
  const emails30d = toNumber(emails30dKey ? item[emails30dKey] : 0);

  const peopleContacted30dKey = findHeader(item, ['external_people_contacted_last_30', 'External People Contacted (Last 30 Days)']);
  const peopleContacted30d = toNumber(peopleContacted30dKey ? item[peopleContacted30dKey] : 0);

  const closedWonKey = findHeader(item, ['closed_won_opportunities_last_fyear', 'Closed Won Opportunities (Last FYear)']);
  const closedWon = toNumber(closedWonKey ? item[closedWonKey] : 0);

  const closedLostKey = findHeader(item, ['closed_lost_opportunities_last_fyear', 'Closed Lost Opportunities (Last FYear)']);
  const closedLost = toNumber(closedLostKey ? item[closedLostKey] : 0);

  const openOppsKey = findHeader(item, ['open_opportunities', 'Open Opportunities']);
  const openOpps = toNumber(openOppsKey ? item[openOppsKey] : 0);

  // Compute firmographic score
  let firmoScore = 0;
  const strongIndustries = ['technology', 'financial services', 'healthcare', 'manufacturing', 'software', 'banking'];
  if (strongIndustries.some(ind => industry.toLowerCase().includes(ind))) firmoScore += 30;
  else if (industry) firmoScore += 15;

  if (annualRevenue >= 50000000 && annualRevenue <= 500000000) firmoScore += 30; // sweet spot
  else if (annualRevenue > 500000000 && annualRevenue <= 2000000000) firmoScore += 25; // enterprise
  else if (annualRevenue >= 10000000) firmoScore += 15;

  if (closedWon === 0 && closedLost === 0) firmoScore += 20; // greenfield
  else if (closedLost > 0 && closedWon === 0) firmoScore += 10; // revisit

  if (openOpps === 0) firmoScore += 10; // no active opp = untapped

  results.push({
    accountId, accountName, accountOwner, accountDomain, industry, accountType,
    engagementLevel, annualRevenue, meetings30d, emails30d, peopleContacted30d,
    closedWon, closedLost, openOpps, firmoScore
  });
}

// Sort by revenue descending, take top 30
results.sort((a, b) => (b.annualRevenue || 0) - (a.annualRevenue || 0));
const top30 = results.slice(0, 30);

console.log(`✅ Extracted ${results.length} total targets, returning top ${top30.length} by revenue`);

return [{ json: { targets: top30, totalTargets: top30.length } }];

